INSERT INTO `zubora_recipes` VALUES (1,'レンチン一回\n簡単オムライス','1.レンチンOKな容器に☆の材料を入れ、よく混ぜる\n2.ピザ用チーズをお好みでかける\n3.△の材料を他の容器に入れて混ぜ、☆にかける\n4.3分レンチンし、最後にケチャップをかけたら完成。','☆ごはん　130ｇ\n☆ツナ缶　1缶(オイルは切る)\n☆ケチャップ　大さじ2\n・チーズ　お好みで\n△卵　1個\n△牛乳　20ｍｌ\n△塩胡椒　適量','1.png','gohan.png tunakan.png chi-zu.png tamago.png gyuunyuu.png kecyappu.png shiokosyou.png','④'),(2,'レンチン1回\nコク旨バタぽんパスタ','1.レンチンＯＫな容器にパスタ、お水を加える\n2.パスタの袋に記載された加熱時間+2分レンチン\n3.ゆで汁大さじ1程度残した状態で☆を入れる\n4.よく混ぜたら完成。','・パスタ100ｇ\n・水250ｍｌ\n☆バター　15ｇ\n☆ツナ缶　1缶(オイルは切る)\n☆ニンニクチューブ　2-3cm\n☆ポン酢　大さじ2\n☆ネギ　好きなだけ\n☆ごま　好きなだけ','2.png','pasta.png bata-.png tunakan.png ninnniku.png negi.png goma.png ponzu.png','①'),(3,'レンチン1回\n和風ツナマヨパスタ','1.レンチンＯＫな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン\n3.パスタに・の材料を入れ、よく混ぜて完成。','☆パスタ　100ｇ\n☆水　230ｍｌ\n☆ツナ缶　1缶(オイルごと)\n☆塩昆布　2つまみ\n☆鶏ガラ　小さじ1\n・マヨネーズ　大さじ2\n・かつお節　1パック\n・ネギ　好きなだけ','3.png','pasta.png tunakan.png konnbu.png tori.png negi.png mayone-zu.png katuobushi.png','①'),(4,'生クリームなし！\n明太クリームパスタ','1.レンチンＯＫな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン\n3.パスタに・の材料を入れ、よく混ぜて完成。','☆パスタ　100ｇ\n☆水　200ｍｌ\n☆鶏ガラ　小さじ1\n☆サラダ油　小さじ1\n・マヨネーズ　大さじ1.5\n・明太子　50ｇ\n・牛乳　大さじ4','4.png','pasta.png tori.png menntaiko.png gyuunyuu.png mayone-zu.png abura.png','①'),(5,'洗い物1つ\n瞬殺パスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+3分レンチン\n3.パスタに・の材料を入れ、よく混ぜて完成。','☆パスタ　100ｇ\n☆水　250ｍｌ\n☆鶏ガラ　小さじ1\n☆ニンニクチューブ　3-5cm\n☆唐辛子　お好みで\n☆オリーブオイル　小さじ2\n☆塩　少々\n・めんつゆ(3倍濃縮)　小さじ1\n・大葉　好きなだけ\n・ブラックペッパー　少々','5.png','pasta.png tori.png ninnniku.png shiokosyou.png abura.png ooba.png tougarashi.png','①'),(6,'仕事終わりでも作れる\nトマたまパスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン\n3.パスタに・の材料を入れ、よく混ぜて完成。','☆パスタ　100ｇ\n☆水　250ｍｌ\n☆コンソメ　小さじ1/2\n☆オリーブオイル　大さじ1\n☆ケチャップ　大さじ2\n☆ベーコン　お好みで\n☆ニンニクチューブ　2-3cm\n・バター　10ｇ\n・卵　1つ','6.png','pasta.png konnsome.png be-kon.png ninnniku.png bata-.png tamago.png abura.png kecyappu.png','①'),(7,'材料入れてレンチンするだけ\nボンゴレビアンコ','1.レンチンOKな容器に全ての材料を入れる\n2.パスタの湯で時間+3分レンチン\n3.よく混ぜて完成。','・パスタ　80ｇ\n・水　180ml\n・ニンニクチューブ　2-5cm\n・ベーコン 　2枚\n・鷹の爪　お好みで\n・オリーブオイル　大さじ1\n・コンソメ　小さじ1/2\n・塩胡椒　適量\n・あさり　お好みで','7.png','pasta.png ninnniku.png be-kon.png konnsome.png kai.png tougarashi.png abura.png shiokosyou.png','①'),(8,'材料入れてレンチンするだけ\nさば缶和風パスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+3分レンチン\n3.よく混ぜてお好みでネギを入れて完成。','☆パスタ　８０ｇ\n☆水　１６０ml\n☆サバ缶（缶汁は含めない）　１００ｇ\n☆玉ねぎ　５０ｇ\n☆オリーブオイル　大さじ１\n☆レモン汁　小さじ１\n☆醤油　大さじ１\n☆ブラックペッパー　適量\n・ネギ　お好みで','8.png','pasta.png sabakan.png tamanegi.png negi.png abura.png remon.png shiokosyou.png syouyu.png','①'),(9,'材料入れてレンチンするだけ\n貧乏人のパスタ','1.レンチンOKな容器に☆の材料を入れる\n2.卵の黄身をつぶす\n3.パスタの湯で時間+6分レンチン\n4.卵とパスタをほぐす\n5.残りをお好みでかけて完成','☆パスタ　８０ｇ\n☆水　１８０ml\n☆オリーブオイル　大さじ１強\n☆ニンニクチューブ　2-5cm\n☆卵　1個\n・粉チーズ　大さじ２～３\n・塩　お好みの味に調整\n・ブラックペッパー　適量','9.png','pasta.png ninnniku.png tamago.png chi-zu.png','①'),(10,'材料入れてレンチンするだけ\nじゃこと野沢菜の納豆パスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+3分レンチン\n3.納豆を付属のタレを入れて混ぜる\n4.レンチンしたパスタに乗せて完成。','☆パスタ　８０ｇ\n☆水　１８０ml\n☆野沢菜の漬物　５０ｇ\n☆じゃこ　１０ｇ\n☆鶏ガラ　小さじ１/２\n☆ごま油　小さじ２\n☆生姜チューブ　小さじ１/２\n☆鷹の爪　お好みで\n・納豆　１パック\n・ネギ　お好みで','10.png','pasta.png jako.png tori.png negi.png abura.png tougarashi.png nattou.png syouga.png','①'),(11,'材料入れてレンチンするだけ\nツナとキムチのバターパスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+3分レンチン\n3.全体を混ぜてお好みで糸唐辛子を入れて完成。','☆パスタ　８０ｇ\n☆水　１５０ml\n☆キムチ　１００ｇ\n☆ツナ缶（オイル）１缶\n☆コチュジャン　大さじ１\n☆バター　１５ｇ\n・糸唐辛子　適量','11.png','pasta.png tunakan.png bata-.png','①'),(12,'材料入れてレンチンするだけ\n和風きのこパスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+3分レンチン\n3.全体を混ぜてお好みで大葉を載せて完成。','☆パスタ　８０ｇ\n☆水　１８０ml\n☆椎茸　２個\n☆ベーコン ２枚\n☆鶏ガラ 小さじ１/２\n☆醤油　小さじ１\n☆ごま油　大さじ１\n☆ニンニクチューブ　小さじ１/２\n・大葉　３枚','12.png','pasta.png kinoko.png be-kon.png tori.png ninnniku.png','①'),(13,'仕事終わりでも作れる\n海苔ボナーラ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン\n3.残りの材料を入れる\n4.空気を含ませるように全体を混ぜて完成。','☆パスタ　100g\n☆水　230ml\n☆鶏ガラ　小さじ1\n☆ニンニクチューブ　3㎝程\n☆ごま油　大さじ1\n・卵　1個\n・マヨネーズ　大さじ2\n・韓国海苔　1パック','13.png','pasta.png tori.png ninnniku.png tamago.png','①'),(14,'仕事終わりでも作れる\n白菜クリームパスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン\n3.残りの材料を入れる全体を混ぜて完成。\n(水分が多いと感じるときには1分ほど馴染ませる)','☆パスタ　100g\n☆ツナ缶　1/2缶(油ごと)\n☆白菜　1枚\n☆ニンニクチューブ　2cm\n☆鶏ガラ　小さじ1\n☆水　200ml\n・マヨネーズ　大さじ2\n・牛乳　大さじ2','14.png','pasta.png tunakan.png ninnniku.png tori.png gyuunyuu.png','①'),(15,'仕事終わりでも作れる\nキムたまボナーラ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン\n3.残りの材料を入れる\n4.空気を入れるように全体を混ぜて完成。','☆パスタ　100g\n☆水　230ml\n☆鶏ガラ　小さじ1\n☆ニンニクチューブ　3㎝程\n☆ごま油　大さじ1\n・卵　1個\n・チーズ　30g\n・キムチ　50g','15.png','pasta.png tori.png ninnniku.png tamago.png chi-zu.png','①'),(16,'レンジで簡単\n濃厚チーズパスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間レンチン\n3.チーズ、牛乳を加えさらに2分レンチン\n4.お好みでブラックペッパーをかけて完成。','☆パスタ　100g\n☆水　200ml\n☆コンソメ　大さじ1/2\n☆バター　10g\n・牛乳　100ml\n・チーズ　80g\n・ブラックペッパー　お好みで','16.png','pasta.png konnsome.png gyuunyuu.png chi-zu.png','①'),(17,'仕事終わりでも作れる\nピリ辛シーフードパスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン\n3.お好みでパセリを散らして完成。','☆パスタ　80g\n☆オリーブオイル　小さじ2\n☆トマトジュース　200ml\n☆水　50ml\n☆コンソメ　小さじ2\n☆一味　お好み\n☆シーフードミックス　お好み\n☆玉ねぎ　30g\n・パセリ　お好み','17.png','pasta.png tomato.png konnsome.png kai.png ebi.png tamanegi.png','①'),(18,'レンチンして混ぜるだけ\n和風クリームパスタ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン\n3.マヨネーズを加え全体をよく混ぜる\n4.お好みで大葉、ごまを散らして完成。','☆パスタ　100g\n☆水　230ml\n☆海老　6個\n☆鶏ガラ　小さじ1\n☆醤油　小さじ1\n☆サラダ油　小さじ1\n・マヨネーズ　大さじ2\n・大葉　お好みで\n・ごま　お好みで','18.png','pasta.png ebi.png tori.png','①'),(19,'22時帰宅でもOK\nバター醤油うどん','1.レンチンOKな容器に☆の材料を入れる\n2.5分レンチン。\n3.有塩バターを加え全体をよく混ぜ、完成。','☆冷凍うどん　１玉\n☆豚肉　50g\n☆しめじ　50g\n☆醤油　大さじ1\n☆砂糖　　大さじ1\n・バター　10g','19.png','udon.png ushi.png kinoko.png bata-.png','④'),(20,'ズボラでも高見え\nレンチンボロネーゼ','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間レンチン。\n3.ケチャップ、ウスターソースを入れて混ぜる\n4.追加で4分レンチン。\n5.全体をよく混ぜ完成。','☆パスタ　100g\n☆水　220cc\n☆粗挽き肉　100g\n☆玉ねぎ　1/2個\n☆コンソメ　大さじ1\n☆ニンニクチューブ　小さじ1\n☆オリーブオイル　大さじ1/2\n☆塩胡椒　適量\n・ケチャップ　大さじ2.5(加熱して酸味飛ばす)\n・ウスターソース　大さじ1\n・粉チーズ　適量\n・パセリ　適量','20.png','pasta.png ushi.png tamanegi.png konnsome.png ninnniku.png chi-zu','①'),(21,'生クリーム不要\nクリームうどん','1.レンチンOKな容器に☆の材料を入れる\n2.うどんの規定時間時間レンチン\n3.全体をよく混ぜ、牛乳をかけて混ぜて完成。','☆冷凍うどん　1玉\n☆マヨネーズ　大さじ2\n☆韓国海苔　3.4枚(3g)\n☆オイスターソース　小さじ1\n(ない時は醤油小さじ1/2)\n☆ニンニクチューブ　2センチ\n☆バター　10g\n・牛乳　大さじ2','21.png','udon.png ninnniku.png bata-.png','④'),(22,'レンジで簡単\nぷるぷる茶碗蒸し','1.マグカップに卵を割り入れ溶く\n2.めんつゆ、水を入れ混ぜる\n3.ふんわりラップをして200W10分加熱\n4.1分蒸らしたら完成。\n(ゆるい場合には様子を見ながら10秒ずつ加熱する)','・卵　1個\n・水　150cc\n・めんつゆ3倍濃縮　大さじ1\n・ちくわ　お好みで\n・三つ葉　適量','22.png','tamago.png','②'),(23,'本当は教えたくない\nとん平焼き','1.ラップを引いた平皿に溶き卵(2個)を入れる\n2.豚肉、もやしを載せ、塩コショウをかける\n3.ラップをし600W4分加熱し粗熱で火を通す\n4.形を整え、ソースなどをトッピングし完成。','☆卵　２個\n☆もやし　1/2袋\n☆豚肉　40g\n☆塩胡椒　少々\n・ソース　お好みで\n・マヨネーズ　お好みで\n・かつお節　お好みで\n・青のり　お好みで','23.png','tamago.png buta.png','②'),(24,'レンチン７分\nヘルシー麻辣湯','1.レンチンOKな容器に☆の材料を入れる\n2.600W5分レンチン\n3.豆乳を入れて全体をよく混ぜる\n4.600W2分レンチン完成。','☆鶏ガラ　小さじ2\n☆醤油　小さじ2\n☆豆板醤　小さじ1\n☆ニンニクチューブ　２センチ\n☆生姜チューブ　２センチ\n☆水　100ml\n☆はるさめ　30-40g\n☆もやし　お好み\n☆小松菜　1株ほど\n☆青梗菜　1株ほど\n☆豚肉　お好みで\n☆海老　お好みで\n・無調整豆乳　200ml','24.png','tori.png ninnniku.png hourennsou.png buta.png ebi.png','④'),(25,'もうプリン買えない？\nレンチンぷるぷるプリン','1.レンチンOKな容器に☆の材料を入れる\n2.600W3分レンチン\n固まらない場合は追加で10秒ずつレンチン完成。','・卵　1個\n・牛乳　130g\n・はちみつ　大さじ1と半分\n・バニラエッセンス　お好みで','25.png','tamago.png gyuunyuu.png hachimitu.png','③'),(26,'簡単！\n豚わさポンパスタ','1.レンチンOKな容器にすべての材料を入れる\n2.600W9分レンチンして完成\n3.お好みでポン酢をかけて食べるとさっぱりします。','・パスタ 100g\n・水 230㎖\n・オリーブオイル 適量\n・コンソメ 1個\n・豚肉 80g\n・大葉 3枚\n・塩昆布 2つまみ\n・わさびチューブ 3cm程度\n・ポン酢 大さじ2','26.png','pasta.png konnsome.png buta.png konnbu.png','①'),(27,'レンジでしっとり\nネギ塩チキン','1.レンチンOKな容器に薄切りにした鶏肉と\n☆の材料を入れる600W5分レンチン\n2.レンジで5分そのまま放置する\n3.ゴマ油とごまをかけて完成。\n(肉に火が通っていない時は追加で1分レンチンする)','☆鶏肉 300g\n☆長ネギ 1本\n☆塩 小さじ1\n☆ブラックペッパー 適量\n☆味の素 8振り\n☆料理酒 大さじ3\n⚫︎ごま油 大さじ1\n⚫︎ごま 適量','27.png','toriniku.png negi.png','②'),(28,'レンジで簡単\n豚もやし蒸し','1.レンチンOKな容器に☆の材料を入れる\n2.600W5分レンチン。\n3.お好みでごま、ネギをかけて完成。','☆料理酒　15ml\n☆醤油　15ml\n☆砂糖　5g\n☆ニンニクチューブ　2cm\n☆ごま油　10ml\n☆もやし　200g\n☆うすぎりの豚肉　200g\n・ごま　お好みで\n・ネギ　お好みで','28.png','ninnniku.png buta.png negi.png','②'),(29,'火を使わない\n10分ナポリタン','1.レンチンOKな容器に☆の材料を入れる\n2.パスタの湯で時間+2分レンチン。\n3.全卵を割り入れよく混ぜる\n4.お好みで粉チーズ、パセリを振りかけて完成。','☆パスタ(5分茹で)　80g\n☆オリーブオイル　小さじ2\n☆水　200ml\n☆ウインナー　3本\n☆パプリカ　30g\n☆コンソメ　小さじ1\n☆ケチャップ　大さじ3\n・卵　1個\n・粉チーズ　お好み\n・パセリ　お好み','29.png','pasta.png uinnna-.png konnsome.png tamago.png chi-zu.png','①'),(30,'菓子パンやめてこれ食べよ！\nレンジで作る米粉ぱん','1.レンチンOKな容器にすべての材料を入れ混ぜる\n2.600W2分レンチン完成。','・卵　1個\n・ココアパウダー 　大さじ１\n・はちみつ 　大さじ１\n・米粉　大さじ３\n・ベーキングパウダー　小さじ1/2\n・米油　小さじ１','30.png','tamago.png hachimitu.png','④'),(31,'ヘルシーおやつ\n濃厚抹茶ケーキ\r\n','1.材料全て入れてよく混ぜる\n2.クッキングシートを敷いた容器に流し込む\n3.600w2分～2分半レンチン\n4.粗熱をとったら冷蔵庫で冷やして完成','・卵　１個\n・米粉　20g\n・無調整豆乳　120ml\n・てんさい糖　20g\n・抹茶パウダー　8g','31.png','','③'),(32,'腸活できる？\nチョコもち\r\n','1.餅を細かくカットして容器に入れる\n2.豆乳を入れふんわりラップし600w2分ほどチン\n3.もちもちするまでよく混ぜる\n4.残りの材料を入れてよく混ぜる\n5.お好みでココアパウダーかけたら完成\r\n','・お餅　１個\n・無調整豆乳　70ml\n・ココアパウダー　大さじ1\n・はちみつ　大さじ1.5','32.png','','③'),(33,'ダイエットに！\n腸活バナナもちロール\r\n','1.絹豆腐をダマがなくなるまでよく混ぜる\n2.残りの☆の材料全て入れて混ぜる\n3.600w1分チンしてよく混ぜる\n4.1つにまとまるまで3回程度繰り返す\n5.ラップの上にのばしてバナナを包んだら完成\r\n','☆豆腐　150ｇ\n☆ココアパウダー　大さじ2\n☆片栗粉　大さじ3\n☆てんさい糖　大さじ1.5\n・バナナ　1本','33.png','','③'),(34,'混ぜてチレンチン！\n濃厚フォンダンショコラ\r\n','1.材料を全て入れてよく混ぜる\n2.容器に生地を流し込んで高カカオチョコを入れる\n3.600w1分チンして完成\n(表面の生感が気になる場合には+20秒レンチン)\r\n','☆卵   １個\n☆米粉  大さじ1.5\n☆ココアパウダー  大さじ1.5\n☆はちみつ  大さじ1\n☆ベーキングパウダー  小さじ1/2\n・高カカオチョコ  1～2枚','34.png','','③'),(35,'罪悪感ゼロ！\n紅茶クッキー','1.材料全部入れて混ぜながらひとつにまとめる\n2.麺棒で薄く伸ばす\n3.表面に焼き目がつくまでレンチンして完成\n(目安：600wレンチン3～4分ほど）','☆紅茶パック  2袋\n☆米粉  60ｇ\n☆卵  40ｇ\n☆はちみつ  15ｇ','35.png','','③'),(36,'混ぜて冷やすだけ\nぷるぷるコーヒーゼリー\r\n','1.材料を全て入れてよく混ぜる\n2.容器に入れて冷蔵庫で2時間ほど冷やして完成\n(はちみつの量はお好みで調整)','・お湯  170ml\n・コーヒー  小さじ2\n・ゼラチン  3ｇ\n・はちみつ　小さじ2','36.png','','③'),(37,'ダイエット中に！\nヨーグルトチーズケーキ\r\n','1.材料をすべて混ぜる\n2.クッキングシートを敷いた耐熱容器に入れる\n3.レンチン500w4分4.冷蔵庫で冷やして完成','・ヨーグルト(無糖)　100g\n・卵　1個\n・てんさい糖　15g\n・米粉　10g','37.png','','③'),(38,'チンして冷やすだけ！\n簡単濃厚チョコブラウニー','1.材料全部入れてよく混ぜる\n2.耐熱容器にクッキングシートを敷いて生地を流す\n3.好きなトッピングをのせる\n4.600w 3分レンチンして冷蔵庫で冷やしたら完成','・豆腐　100g\n・ココアパウダー　大さじ1\n・米粉　大さじ2\n・はちみつ　15～20g\n・好きなトッピング　お好みで','38.png','','③'),(39,'罪悪感無く食べたい！\n腸活きなこチョコ\n','1.材料全部混ぜる\n2.好きな型や容器に流し込む\n3.冷蔵庫で30分以上冷やして完成','・きな粉  20g\n・ココナッツオイル   20g\n・はちみつ  10g','39.png','','③'),(40,'グルテンフリー\n揚げないドーナツ','1.☆の材料全て入れてよく混ぜる\n2.ドーナツ型に流し込む\n3.500w3分レンチンして完成','☆卵   １個\n☆米粉 40g\n☆無調整豆乳  30ml\n☆はちみつ  大さじ1\n☆ココアパウダー  大さじ1\n☆ベーキングパウダー  3g','40.png','','③'),(41,'ご飯が止まらない\n豚もやしピーマン','1.レンチンOKな容器に☆の材料を入れる\n2.レンジで600W7分レンチン\n3.片栗粉を入れる\n4.全体を混ぜて完成','☆豚肉　100g\n☆料理酒 大さじ2\n☆もやし 1/2袋\n☆ピーマン 1個\n☆鶏ガラ 小さじ2\n☆みりん 大さじ1\n☆醤油 大さじ1/2\n☆ニンニクチューブ 小さじ1\n・片栗粉 小さじ2','41.png','','②'),(42,'簡単醤油ソーメン','1.☆の調味料を合わせて600w2分加熱\n2.そうめんとトッピングの具をのせる\n※かつお節はたっぷり入れてください','・そうめん　1輪\n☆水　200ml\n☆鶏ガラ　小さじ1\n☆ごま油　小さじ1\n☆醤油　大さじ1\n☆みりん　大さじ1\n☆コチュジャン　小さじ1/3\n☆ニンニクチューブ　小さじ1/3\n☆砂糖　小さじ1/3\n・トッピング お好みで','42.png','','④'),(43,'グルテンフリー\nお豆腐ピザパン','1.豆腐は水切りしてダマがなくなるまでよく混ぜる\n2.残りの☆を入れて1つにまとめながら混ぜる\n3.2つに分けて平たくして中心にくぼみをつける\n4.トッピングしたら600w2分レンチンして完成\n','・豆腐   100ｇ\n☆米粉  80ｇ\n☆ベーキングパウダー  3g\n・トッピングはお好みで','43.png','','④'),(44,'レンジ一撃！\n鶏肉のみぞれ煮\n','1.耐熱容器に大根をすりおろして入れる\n2.大根に鶏肉を沈める\n3.ふんわりラップしてレンジ600w6分加熱\n4.全体を混ぜて小ネギを散らしたら完成\n','・大根　1/8本\n・鶏肉　250～300g\n・めんつゆ(3倍濃縮)　大さじ3\n・酢　大さじ1\n・ごま油　大さじ1/2\n・小ネギ　適量','44.png','','②'),(45,'レンチン5分で簡単\n豚バラもやし\r\n','1.耐熱容器に・の材料を入れる\n2.ふんわりラップで600w5分加熱\n3.その間に☆の材料を混ぜておく\n4.たれと△をお好みでかけて完成\r\n','・豚肉　120g\n・もやし　1袋\n・豆苗　1袋\n△ごま　適量\n△ブラックペッパー　適量\n△ネギ　適量\n☆ポン酢　大さじ2\n☆コチュジャン　小さじ2\n☆ごま油　小さじ1\n☆ニンニクチューブ　小さじ1','45.png','','②'),(46,'小腹がすいたらこれ食べて！\n脂肪燃焼スープ\r\n','1.わかめを水で戻す\n2.★の材料を入れる\n3.レンジで１分加熱する\n4.ごまをかけたら完成','☆豆腐　1パック\n☆キムチ　30ｇ\n☆乾燥わかめ　大さじ1\n☆鶏ガラ　小さじ1\n☆お湯　200ml\n・ごま　適量','46.png','','②'),(47,'抱えて食べたい！？\n豆苗と卵のナムル','1.豆苗を袋に入れてレンジ500W1分加熱\n2.水気を切る\n3.すべての材料を入れる\n4.全体をよく混ぜ完成\r\n','・豆苗　1袋\n・カニカマ　5本\n・鶏ガラ　小さじ1\n・ごま油　小さじ1\n・いりごま　大さじ1/2\n・ゆで卵　2個','47.png','','②'),(48,'揚げずにヘルシー\nのり塩チップス','1.ライスペーパーを水に軽く浸す\n2.クッキングシートの上に置く\n3.オイルを少量塗り広げる\n4.青のりと塩をかける\n5.600w2分ほどレンチンして完成','・ライスペーパー　1枚\n・青のり　適量\n・塩　適量\n・好きなオイル　少量','48.png','','⑤'),(49,'レンチン1発高見えご飯\n卵と豆腐のキッシュ','1.絹豆腐と卵を入れてなめらかになるまで混ぜる\n2.コンソメ・塩胡椒を入れてまた混ぜる\n3.ピザ用チーズ・ブロッコリー・海老を乗せる\n4.ラップをしてレンジ600w5分加熱して完成','・豆腐　150g\n・卵　1個\n・コンソメ　小さじ1\n・塩胡椒　5振りくらい\n・チーズ　ふたつかみくらい\n・ブロッコリー　適量\n・海老　適量','49.png','','②');
